// Add to transformer_inference.cpp
bool TransformerInference::loadTokenizerFromGGUF(const QString& ggufPath) {
    GGUFContext* gguf = gguf_init_from_file(ggufPath.toStdString().c_str(), nullptr);
    if (!gguf) {
        qCritical() << "Failed to load GGUF for tokenizer:" << ggufPath;
        return false;
    }
    
    // Load vocabulary from GGUF
    int vocabSize = gguf_get_key_int(gguf, "tokenizer.ggml.vocab_size");
    qInfo() << "Loading vocabulary with size:" << vocabSize;
    
    for (int i = 0; i < vocabSize; ++i) {
        QString key = QString("tokenizer.ggml.token_%1").arg(i);
        const char* tokenText = gguf_get_key_str(gguf, key.toStdString().c_str());
        
        if (tokenText) {
            QString tokenStr = QString::fromUtf8(tokenText);
            m_tokenizer.idToToken[i] = tokenStr;
            m_tokenizer.tokenToId[tokenStr] = i;
            
            // Store special tokens
            if (tokenStr == "<unk>") m_tokenizer.unkToken = tokenStr;
            else if (tokenStr == "<s>") m_tokenizer.bosToken = tokenStr;
            else if (tokenStr == "</s>") m_tokenizer.eosToken = tokenStr;
            else if (tokenStr == "<pad>") m_tokenizer.padToken = tokenStr;
        }
    }
    
    gguf_free(gguf);
    qInfo() << "Loaded" << m_tokenizer.idToToken.size() << "tokens from GGUF";
    return true;
}

QString TransformerInference::detokenize(const std::vector<int32_t>& tokens) const {
    if (m_tokenizer.idToToken.isEmpty()) {
        qWarning() << "No vocabulary loaded - cannot detokenize";
        return "";
    }
    
    QString result;
    for (int32_t tokenId : tokens) {
        if (m_tokenizer.idToToken.contains(tokenId)) {
            QString token = m_tokenizer.idToToken[tokenId];
            
            // Handle special tokens
            if (token == m_tokenizer.unkToken || 
                token == m_tokenizer.bosToken || 
                token == m_tokenizer.eosToken ||
                token == m_tokenizer.padToken) {
                continue; // Skip special tokens
            }
            
            // Handle byte-level tokens (common in modern tokenizers)
            if (token.startsWith("<0x") && token.endsWith(">")) {
                bool ok;
                int byteValue = token.mid(3, token.length() - 4).toInt(&ok, 16);
                if (ok && byteValue >= 0 && byteValue <= 255) {
                    result += QChar(static_cast<ushort>(byteValue));
                    continue;
                }
            }
            
            result += token;
        } else {
            qDebug() << "Unknown token ID:" << tokenId;
        }
    }
    
    // Clean up common artifacts
    result = result.replace("▁", " ");  // SentencePiece space marker
    result = result.replace("Ġ", " ");  // GPT-style space marker
    result = result.replace("+", " ");  // Some tokenizers use + for spaces
    result = result.trimmed();
    
    return result;
}

std::vector<int32_t> TransformerInference::tokenize(const QString& text) const {
    if (m_tokenizer.tokenToId.isEmpty()) {
        qWarning() << "No vocabulary loaded - cannot tokenize";
        return {};
    }
    
    // Simple whitespace tokenization (you'll want to implement proper BPE)
    std::vector<int32_t> tokens;
    QStringList words = text.split(QRegularExpression("\\s+"), Qt::SkipEmptyParts);
    
    for (const QString& word : words) {
        if (m_tokenizer.tokenToId.contains(word)) {
            tokens.push_back(m_tokenizer.tokenToId[word]);
        } else {
            // Handle unknown words - try subword tokenization
            QString remaining = word;
            while (!remaining.isEmpty()) {
                bool found = false;
                // Try decreasing substring lengths
                for (int len = remaining.length(); len > 0; --len) {
                    QString subword = remaining.left(len);
                    if (m_tokenizer.tokenToId.contains(subword)) {
                        tokens.push_back(m_tokenizer.tokenToId[subword]);
                        remaining = remaining.mid(len);
                        found = true;
                        break;
                    }
                }
                if (!found) {
                    // Use unknown token
                    if (m_tokenizer.tokenToId.contains(m_tokenizer.unkToken)) {
                        tokens.push_back(m_tokenizer.tokenToId[m_tokenizer.unkToken]);
                    }
                    break;
                }
            }
        }
    }
    
    return tokens;
}
